//! Divan micro-benchmarks for the SEC2 curves.
//!
//! Every curve gets the exact same set of benchmarks, generated by the
//! [`curve_benches!`] macro. The macro takes the curve module path as a
//! parameter and emits a self-contained module covering the field, the scalar
//! field and the elliptic-curve group operations (serialization, addition,
//! multiplication, inverse, square, scalar multiplication, ...).
//!
//! Run with:
//!
//! ```text
//! cargo bench
//! cargo bench -- p256r1            # only the p256r1 curve
//! cargo bench -- p256r1::field     # only the field operations of p256r1
//! ```

fn main() {
    divan::main();
}

/// Generate the full benchmark suite for a single curve.
///
/// * `$feature` — the cargo feature gating the curve (so the benches only
///   compile when the curve is available).
/// * `$name` — the module name the benchmarks live under (also the prefix that
///   shows up in the divan report, e.g. `curves::p256r1::field::mul`).
/// * `$curve` — the path to the curve module providing `FieldElement`,
///   `Scalar`, `Point`, `PointAffine` and `Curve`.
macro_rules! curve_benches {
    ($feature:literal, $name:ident, $curve:path) => {
        #[cfg(feature = $feature)]
        mod $name {
            use $curve::*;

            // --- sample values -------------------------------------------------

            /// A non-trivial, full-width field element (the generator's x).
            fn fe_a() -> FieldElement {
                Curve::generator().0.clone()
            }

            /// A second, distinct full-width field element (the generator's y).
            fn fe_b() -> FieldElement {
                Curve::generator().1.clone()
            }

            /// A non-trivial scalar (a reduced product, so always `< order`).
            fn sc_a() -> Scalar {
                let mut s = Scalar::from_u64(0x0123_4567_89ab_cdef);
                for _ in 0..5 {
                    s = s.square();
                }
                s
            }

            /// A second, distinct non-trivial scalar.
            fn sc_b() -> Scalar {
                let mut s = Scalar::from_u64(0xfedc_ba98_7654_3210);
                for _ in 0..5 {
                    s = s.square();
                }
                s
            }

            /// The generator in projective coordinates.
            fn point() -> Point {
                Point::generator()
            }

            /// `2 * generator`, distinct from the generator so that adding the
            /// two exercises the generic (non-doubling) addition path.
            fn point2() -> Point {
                Point::from_affine(&PointAffine::generator().double())
            }

            /// The generator in affine coordinates.
            fn affine() -> PointAffine {
                PointAffine::generator()
            }

            /// `2 * generator` in affine coordinates.
            fn affine2() -> PointAffine {
                PointAffine::generator().double()
            }

            // --- prime field F(p) ---------------------------------------------
            mod field {
                use super::*;
                use divan::{black_box, Bencher};

                #[divan::bench]
                fn add(bencher: Bencher) {
                    let (a, b) = (fe_a(), fe_b());
                    bencher.bench(|| black_box(&a) + black_box(&b));
                }

                #[divan::bench]
                fn sub(bencher: Bencher) {
                    let (a, b) = (fe_a(), fe_b());
                    bencher.bench(|| black_box(&a) - black_box(&b));
                }

                #[divan::bench]
                fn mul(bencher: Bencher) {
                    let (a, b) = (fe_a(), fe_b());
                    bencher.bench(|| black_box(&a) * black_box(&b));
                }

                #[divan::bench]
                fn square(bencher: Bencher) {
                    let a = fe_a();
                    bencher.bench(|| black_box(&a).square());
                }

                #[divan::bench]
                fn double(bencher: Bencher) {
                    let a = fe_a();
                    bencher.bench(|| black_box(&a).double());
                }

                #[divan::bench]
                fn neg(bencher: Bencher) {
                    let a = fe_a();
                    bencher.bench(|| -black_box(&a));
                }

                #[divan::bench]
                fn inverse(bencher: Bencher) {
                    let a = fe_a();
                    bencher.bench(|| black_box(&a).inverse());
                }

                #[divan::bench]
                fn sqrt(bencher: Bencher) {
                    // square first so the input is guaranteed to be a residue
                    let a = fe_a().square();
                    bencher.bench(|| black_box(&a).sqrt());
                }

                #[divan::bench]
                fn to_bytes(bencher: Bencher) {
                    let a = fe_a();
                    bencher.bench(|| black_box(&a).to_bytes());
                }

                #[divan::bench]
                fn from_bytes(bencher: Bencher) {
                    let bytes = fe_a().to_bytes();
                    bencher.bench(|| FieldElement::from_bytes(black_box(&bytes)));
                }
            }

            // --- scalar field F(n) --------------------------------------------
            mod scalar {
                use super::*;
                use divan::{black_box, Bencher};

                #[divan::bench]
                fn add(bencher: Bencher) {
                    let (a, b) = (sc_a(), sc_b());
                    bencher.bench(|| black_box(&a) + black_box(&b));
                }

                #[divan::bench]
                fn sub(bencher: Bencher) {
                    let (a, b) = (sc_a(), sc_b());
                    bencher.bench(|| black_box(&a) - black_box(&b));
                }

                #[divan::bench]
                fn mul(bencher: Bencher) {
                    let (a, b) = (sc_a(), sc_b());
                    bencher.bench(|| black_box(&a) * black_box(&b));
                }

                #[divan::bench]
                fn square(bencher: Bencher) {
                    let a = sc_a();
                    bencher.bench(|| black_box(&a).square());
                }

                #[divan::bench]
                fn inverse(bencher: Bencher) {
                    let a = sc_a();
                    bencher.bench(|| black_box(&a).inverse());
                }

                #[divan::bench]
                fn to_bytes(bencher: Bencher) {
                    let a = sc_a();
                    bencher.bench(|| black_box(&a).to_bytes());
                }

                #[divan::bench]
                fn from_bytes(bencher: Bencher) {
                    let bytes = sc_a().to_bytes();
                    bencher.bench(|| Scalar::from_bytes(black_box(&bytes)));
                }
            }

            // --- elliptic curve group -----------------------------------------
            mod point {
                use super::*;
                use divan::{black_box, Bencher};

                #[divan::bench]
                fn add(bencher: Bencher) {
                    let (p, q) = (point(), point2());
                    bencher.bench(|| black_box(&p) + black_box(&q));
                }

                #[divan::bench]
                fn double(bencher: Bencher) {
                    let p = point();
                    bencher.bench(|| black_box(&p) + black_box(&p));
                }

                #[divan::bench]
                fn scalar_mul(bencher: Bencher) {
                    let (p, k) = (point(), sc_a());
                    bencher.bench(|| black_box(&p) * black_box(&k));
                }

                #[divan::bench]
                fn to_affine(bencher: Bencher) {
                    // G + 2G = 3G is a genuine projective point (z != 1), so the
                    // benchmark exercises the modular inversion rather than the
                    // `z == 1` fast path.
                    let p = &point() + &point2();
                    bencher.bench(|| black_box(&p).to_affine());
                }

                #[divan::bench]
                fn from_affine(bencher: Bencher) {
                    let a = affine();
                    bencher.bench(|| Point::from_affine(black_box(&a)));
                }

                #[divan::bench]
                fn affine_add(bencher: Bencher) {
                    let (a, b) = (affine(), affine2());
                    bencher.bench(|| black_box(&a) + black_box(&b));
                }

                #[divan::bench]
                fn affine_double(bencher: Bencher) {
                    let a = affine();
                    bencher.bench(|| black_box(&a).double());
                }

                #[divan::bench]
                fn compress(bencher: Bencher) {
                    let a = affine();
                    bencher.bench(|| black_box(&a).compress());
                }

                #[divan::bench]
                fn decompress(bencher: Bencher) {
                    let a = affine();
                    let (x, sign) = a.compress();
                    let x = x.clone();
                    bencher.bench(|| PointAffine::decompress(black_box(&x), sign));
                }
            }
        }
    };
}

curve_benches!("p192k1", p192k1, eccoxide::curve::sec2::p192k1);
curve_benches!("p192r1", p192r1, eccoxide::curve::sec2::p192r1);
curve_benches!("p224k1", p224k1, eccoxide::curve::sec2::p224k1);
curve_benches!("p224r1", p224r1, eccoxide::curve::sec2::p224r1);
curve_benches!("p256k1", p256k1, eccoxide::curve::sec2::p256k1);
curve_benches!("p256r1", p256r1, eccoxide::curve::sec2::p256r1);
curve_benches!("p384r1", p384r1, eccoxide::curve::sec2::p384r1);
curve_benches!("p521r1", p521r1, eccoxide::curve::sec2::p521r1);
